<?php
/**
 * WhatsApp number in international format, digits only (no +, no dashes).
 * An Israeli mobile looks like 9725XXXXXXXX.
 */
const GDI_WHATSAPP = '4917687231982';

add_action('after_setup_theme', function () {
    add_theme_support('title-tag');
});

/**
 * Pre-launch: keep the site out of search results entirely.
 *
 * Enforced in the theme, not just via the blog_public option, because the
 * database is not part of the SFTP deploy - production would otherwise stay
 * crawlable. Remove this whole block (and re-enable "Search engine visibility"
 * in Settings > Reading) at launch.
 *
 * noindex is what actually keeps a page out of the results; robots.txt only
 * asks crawlers not to fetch it, and a Disallow'd URL can still be listed if
 * it is linked from somewhere else.
 */
add_action('wp_head', function () {
    echo '<meta name="robots" content="noindex, nofollow, noarchive, nosnippet, noimageindex">' . "\n";
}, 1);

add_filter('wp_robots', function (array $robots): array {
    return ['noindex' => true, 'nofollow' => true];
}, 99);

add_action('send_headers', function () {
    header('X-Robots-Tag: noindex, nofollow, noarchive, nosnippet, noimageindex');
});

add_filter('robots_txt', function (): string {
    return "User-agent: *\nDisallow: /\n";
}, 99);

add_action('wp_enqueue_scripts', function () {
    wp_enqueue_style('gdi-font', 'https://fonts.googleapis.com/css2?family=Heebo:wght@400;700;900&display=swap', [], null);

    // Version from the file's mtime, not the theme header: the header version
    // never changes on deploy, so the CSS URL stayed identical and Cloudflare
    // kept serving a stale copy for its full 4h TTL. mtime changes whenever the
    // file actually changes, which is exactly when the cache should be busted.
    $gdi_css = get_stylesheet_directory() . '/style.css';
    $gdi_ver = file_exists($gdi_css) ? filemtime($gdi_css) : wp_get_theme()->get('Version');
    wp_enqueue_style('gdi', get_stylesheet_uri(), ['gdi-font'], $gdi_ver);
});

/**
 * Wraps each word of $text in a <span> carrying a 1-based index custom
 * property, for the CSS scroll-driven word-reveal effect. Splits on
 * whitespace only (never per-letter) so Hebrew niqqud and screen readers
 * stay intact. Output is escaped with esc_html in case this ever wraps
 * editable/translatable content instead of a hardcoded string.
 *
 * A literal "\n" in $text forces a manual <br> at that point (e.g. to keep
 * a phrase off the previous line) while keeping one continuous --i count
 * across the break, so the reveal animation still flows word-by-word.
 */
function gdi_word_spans(string $text): string {
    $lines = preg_split('/\r\n|\r|\n/', trim($text));
    $words_per_line = array_map(
        fn($line) => array_values(array_filter(preg_split('/\s+/u', trim($line)), 'strlen')),
        $lines
    );
    $n = array_sum(array_map('count', $words_per_line));
    $i = 0;
    $rendered_lines = [];
    foreach ($words_per_line as $line_words) {
        $spans = [];
        foreach ($line_words as $word) {
            $i++;
            $spans[] = sprintf('<span class="w" style="--i:%d">%s</span>', $i, esc_html($word));
        }
        $rendered_lines[] = implode(' ', $spans);
    }
    return sprintf('<span class="sec" style="--n:%d">%s</span>', max($n, 1), implode('<br>', $rendered_lines));
}

